def compress_history(
    history: list[dict],
    keep_recent_turns: int = 4,
    model: str = "claude-haiku-4-5",  # use Haiku — summarization is cheap
) -> list[dict]:
    """
    Summarize all but the last keep_recent_turns exchanges into one system note.
    """
    keep = keep_recent_turns * 2
    if len(history) <= keep:
        return history

    old = history[:-keep]
    recent = history[-keep:]

    # Build a transcript of old turns
    transcript = "\n".join(
        f"{m['role'].upper()}: {m['content']}" for m in old
    )

    summary_resp = client.messages.create(
        model=model,
        max_tokens=256,
        messages=[
            {
                "role": "user",
                "content": (
                    "Summarize this conversation in 3-5 sentences, preserving key facts "
                    "and decisions the assistant made:\n\n" + transcript
                ),
            }
        ],
    )
    summary = summary_resp.content[0].text

    # Inject summary as a synthetic context message
    context_msg = {
        "role": "user",
        "content": f"[Earlier conversation summary: {summary}]",
    }
    ack_msg = {"role": "assistant", "content": "Understood."}

    return [context_msg, ack_msg] + recent

from collections import defaultdict
import statistics

token_log: dict[str, list[int]] = defaultdict(list)

def log_usage(endpoint: str, input_tokens: int, output_tokens: int) -> None:
    token_log[endpoint].append(input_tokens)

def efficiency_report() -> None:
    for endpoint, tokens in token_log.items():
        if len(tokens) < 10:
            continue
        avg = statistics.mean(tokens)
        p90 = sorted(tokens)[int(len(tokens) * 0.9)]
        print(f"{endpoint}: avg={avg:.0f} p90={p90:.0f} samples={len(tokens)}")

